import React, { useState } from 'react';

const App = () => {
  const [username, setUsername] = useState('');
  const [message, setMessage] = useState('');
  const [typing, setTyping] = useState(false);
  const [chatHistory, setChatHistory] = useState([]);

  const handleUsernameChange = (event) => {
    setUsername(event.target.value);
  };

  const handleMessageChange = (event) => {
    setMessage(event.target.value);
  };

  const handleTyping = () => {
    setTyping(true);
  };

  const handleSendMessage = () => {
    if (username && message) {
      setChatHistory((prevHistory) => [...prevHistory, { username, message }]);
      setMessage('');
    }
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-lg shadow-md w-96">
        <div className="flex justify-between items-center mb-4">
          <div className="flex items-center">
            <div className="bg-[#B7D7CD] p-2 rounded-full mr-2" />
            <input type="text" value={username} onChange={handleUsernameChange} placeholder="Username" className="bg-transparent appearance-none rounded-lg py-2 px-4 text-white" />
          </div>
          <input type="text" value={message} onChange={handleMessageChange} placeholder="Message" className="w-full bg-transparent appearance-none rounded-lg py-2 px-4 text-white" />
        </div>
        <button onClick={handleTyping} className="bg-[#411C56] hover:bg-[#C06C88] text-[#B7D7CD] py-2 px-4 rounded">Typing...</button>
        <button onClick={handleSendMessage} className="bg-[#411C56] hover:bg-[#C06C88] text-[#B7D7CD] py-2 px-4 rounded">Send</button>
        <div className="flex flex-col mt-4">
          {chatHistory.map((item, index) => (
            <div key={index} className="bg-[#B7D7CD] p-2 mb-2 rounded-lg">
              <span className="text-[#411C56] font-bold">{item.username}</span>: {item.message}
            </div>
          ))}
        </div>
        {typing && <div className="bg-[#C06C88] p-2 mb-2 rounded-lg">Typing...</div>}
      </div>
    </div>
  );
};

export default App;
